import{_ as s,o as e,c as n,a2 as o}from"./chunks/framework.BRk9mohw.js";const u=JSON.parse('{"title":"上下文","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/context.md","filePath":"concepts/context.md"}'),t={name:"concepts/context.md"};function l(c,a,p,i,r,d){return e(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="上下文" tabindex="-1">上下文 <a class="header-anchor" href="#上下文" aria-label="Permalink to &quot;上下文&quot;">​</a></h1><h1 id="上下文-1" tabindex="-1">上下文 <a class="header-anchor" href="#上下文-1" aria-label="Permalink to &quot;上下文&quot;">​</a></h1><p>&quot;上下文&quot;是<strong>OpenClaw 发送给模型进行运行的所有内容</strong>。它以模型的<strong>上下文窗口</strong>（令牌限制）为界。</p><p>初学者心智模型：</p><ul><li><strong>系统提示</strong>（OpenClaw 构建）：规则、工具、技能列表、时间/运行时以及注入的工作空间文件。</li><li><strong>对话历史</strong>：您的消息 + 该会话中助手的回复。</li><li><strong>工具调用/结果 + 附件</strong>：命令输出、文件读取、图像/音频等。</li></ul><p>上下文与&quot;记忆&quot;不同：记忆可以存储在磁盘上并在以后重新加载；上下文是模型当前窗口内的内容。</p><h2 id="快速开始-检查上下文" tabindex="-1">快速开始（检查上下文） <a class="header-anchor" href="#快速开始-检查上下文" aria-label="Permalink to &quot;快速开始（检查上下文）&quot;">​</a></h2><ul><li><code>/status</code> → 快速&quot;我的窗口有多满？&quot;视图 + 会话设置。</li><li><code>/context list</code> → 注入的内容 + 粗略大小（每个文件 + 总计）。</li><li><code>/context detail</code> → 更深层次的分部：每个文件、每个工具模式大小、每个技能条目大小以及系统提示大小。</li><li><code>/usage tokens</code> → 将每回复使用情况追加到正常回复的页脚。</li><li><code>/compact</code> → 将旧历史总结为紧凑条目以释放窗口空间。</li></ul><p>另见：<a href="/tools/slash-commands.html">斜杠命令</a>、<a href="/reference/token-use.html">令牌使用与成本</a>、<a href="/concepts/compaction.html">压缩</a>。</p><h2 id="示例输出" tabindex="-1">示例输出 <a class="header-anchor" href="#示例输出" aria-label="Permalink to &quot;示例输出&quot;">​</a></h2><p>值因模型、提供商、工具策略以及工作空间中的内容而异。</p><h3 id="context-list" tabindex="-1"><code>/context list</code> <a class="header-anchor" href="#context-list" aria-label="Permalink to &quot;\`/context list\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown</span></span>
<span class="line"><span>Workspace: &lt;workspaceDir&gt;</span></span>
<span class="line"><span>Bootstrap max/file: 20,000 chars</span></span>
<span class="line"><span>Sandbox: mode=non-main sandboxed=false</span></span>
<span class="line"><span>System prompt (run): 38,412 chars (~9,603 tok) (Project Context 23,901 chars (~5,976 tok))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Injected workspace files:</span></span>
<span class="line"><span>- AGENTS.md: OK | raw 1,742 chars (~436 tok) | injected 1,742 chars (~436 tok)</span></span>
<span class="line"><span>- SOUL.md: OK | raw 912 chars (~228 tok) | injected 912 chars (~228 tok)</span></span>
<span class="line"><span>- TOOLS.md: TRUNCATED | raw 54,210 chars (~13,553 tok) | injected 20,962 chars (~5,241 tok)</span></span>
<span class="line"><span>- IDENTITY.md: OK | raw 211 chars (~53 tok) | injected 211 chars (~53 tok)</span></span>
<span class="line"><span>- USER.md: OK | raw 388 chars (~97 tok) | injected 388 chars (~97 tok)</span></span>
<span class="line"><span>- HEARTBEAT.md: MISSING | raw 0 | injected 0</span></span>
<span class="line"><span>- BOOTSTRAP.md: OK | raw 0 chars (~0 tok) | injected 0 chars (~0 tok)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skills list (system prompt text): 2,184 chars (~546 tok) (12 skills)</span></span>
<span class="line"><span>Tools: read, edit, write, exec, process, browser, message, sessions_send, …</span></span>
<span class="line"><span>Tool list (system prompt text): 1,032 chars (~258 tok)</span></span>
<span class="line"><span>Tool schemas (JSON): 31,988 chars (~7,997 tok) (counts toward context; not shown as text)</span></span>
<span class="line"><span>Tools: (same as above)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session tokens (cached): 14,250 total / ctx=32,000</span></span></code></pre></div><h3 id="context-detail" tabindex="-1"><code>/context detail</code> <a class="header-anchor" href="#context-detail" aria-label="Permalink to &quot;\`/context detail\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown (detailed)</span></span>
<span class="line"><span>…</span></span>
<span class="line"><span>Top skills (prompt entry size):</span></span>
<span class="line"><span>- frontend-design: 412 chars (~103 tok)</span></span>
<span class="line"><span>- oracle: 401 chars (~101 tok)</span></span>
<span class="line"><span>… (+10 more skills)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Top tools (schema size):</span></span>
<span class="line"><span>- browser: 9,812 chars (~2,453 tok)</span></span>
<span class="line"><span>- exec: 6,240 chars (~1,560 tok)</span></span>
<span class="line"><span>… (+N more tools)</span></span></code></pre></div><h2 id="什么计入上下文窗口" tabindex="-1">什么计入上下文窗口 <a class="header-anchor" href="#什么计入上下文窗口" aria-label="Permalink to &quot;什么计入上下文窗口&quot;">​</a></h2><p>模型接收的所有内容都计入，包括：</p><ul><li>系统提示（所有部分）。</li><li>对话历史。</li><li>工具调用 + 工具结果。</li><li>附件/记录（图像/音频/文件）。</li><li>压缩摘要和修剪产物。</li><li>提供商&quot;包装器&quot;或隐藏标头（不可见，仍计入）。</li></ul><h2 id="openclaw-如何构建系统提示" tabindex="-1">OpenClaw 如何构建系统提示 <a class="header-anchor" href="#openclaw-如何构建系统提示" aria-label="Permalink to &quot;OpenClaw 如何构建系统提示&quot;">​</a></h2><p>系统提示<strong>由 OpenClaw 所有</strong>，每轮重新构建。它包括：</p><ul><li>工具列表 + 简短描述。</li><li>技能列表（仅元数据；见下文）。</li><li>工作空间位置。</li><li>时间（UTC + 配置的用户转换时间）。</li><li>运行时元数据（主机/操作系统/模型/推理）。</li><li>在 <strong>Project Context</strong> 下注入的工作空间引导文件。</li></ul><p>完整分解：<a href="/concepts/system-prompt.html">系统提示</a>。</p><h2 id="注入的工作空间文件-项目上下文" tabindex="-1">注入的工作空间文件（项目上下文） <a class="header-anchor" href="#注入的工作空间文件-项目上下文" aria-label="Permalink to &quot;注入的工作空间文件（项目上下文）&quot;">​</a></h2><p>默认情况下，OpenClaw 注入一组固定的工作空间文件（如果存在）：</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code>（仅首次运行）</li></ul><p>大文件使用 <code>agents.defaults.bootstrapMaxChars</code>（默认 <code>20000</code> 字符）按文件截断。OpenClaw 还使用 <code>agents.defaults.bootstrapTotalMaxChars</code>（默认 <code>150000</code> 字符）在文件间强制执行总引导注入上限。<code>/context</code> 显示<strong>原始 vs 注入</strong>大小以及是否发生截断。</p><p>发生截断时，运行时可以在 Project Context 下注入警告块。配置此使用 <code>agents.defaults.bootstrapPromptTruncationWarning</code>（<code>off</code>、<code>once</code>、<code>always</code>；默认 <code>once</code>）。</p><h2 id="技能-按需注入-vs-加载" tabindex="-1">技能：按需注入 vs 加载 <a class="header-anchor" href="#技能-按需注入-vs-加载" aria-label="Permalink to &quot;技能：按需注入 vs 加载&quot;">​</a></h2><p>系统提示包含一个紧凑的<strong>技能列表</strong>（名称 + 描述 + 位置）。此列表有真实开销。</p><p>默认情况下，技能指令<strong>不</strong>包含。模型被期望在需要时 <code>read</code> 技能的 <code>SKILL.md</code>。</p><h2 id="工具-有两种成本" tabindex="-1">工具：有两种成本 <a class="header-anchor" href="#工具-有两种成本" aria-label="Permalink to &quot;工具：有两种成本&quot;">​</a></h2><p>工具以两种方式影响上下文：</p><ol><li>系统提示中的<strong>工具列表</strong>文本（如您所见的&quot;Tooling&quot;）。</li><li><strong>工具模式</strong>（JSON）。这些被发送给模型以便它可以调用工具。它们计入上下文，尽管您看不到它们作为纯文本。</li></ol><p><code>/context detail</code> 分解最大的工具模式，以便您可以看到什么占主导。</p><h2 id="命令、指令和-内联快捷方式" tabindex="-1">命令、指令和&quot;内联快捷方式&quot; <a class="header-anchor" href="#命令、指令和-内联快捷方式" aria-label="Permalink to &quot;命令、指令和&quot;内联快捷方式&quot;&quot;">​</a></h2><p>斜杠命令由网关处理。有几种不同的行为：</p><ul><li><strong>独立命令</strong>：仅是 <code>/...</code> 的消息作为命令运行。</li><li><strong>指令</strong>：<code>/think</code>、<code>/verbose</code>、<code>/reasoning</code>、<code>/elevated</code>、<code>/model</code>、<code>/queue</code> 在模型看到消息之前被剥离。 <ul><li>仅指令消息持久化会话设置。</li><li>正常消息中的内联指令作为每消息提示运行。</li></ul></li><li><strong>内联快捷方式</strong>（仅允许列表中的发送者）：某些正常消息内的 <code>/...</code> 令牌可以立即运行（例如&quot;hey /status&quot;），并在模型看到剩余文本之前被剥离。</li></ul><p>详情：<a href="/tools/slash-commands.html">斜杠命令</a>。</p><h2 id="会话、压缩和修剪-什么持久化" tabindex="-1">会话、压缩和修剪（什么持久化） <a class="header-anchor" href="#会话、压缩和修剪-什么持久化" aria-label="Permalink to &quot;会话、压缩和修剪（什么持久化）&quot;">​</a></h2><p>什么在消息间持久化取决于机制：</p><ul><li><strong>正常历史</strong>持久化在会话记录中，直到按策略压缩/修剪。</li><li><strong>压缩</strong>将摘要持久化到记录中，并保持最近的消息完整。</li><li><strong>修剪</strong>从运行的<em>内存中</em>提示中删除旧工具结果，但不重写记录。</li></ul><p>文档：<a href="/concepts/session.html">会话</a>、<a href="/concepts/compaction.html">压缩</a>、<a href="/concepts/session-pruning.html">会话修剪</a>。</p><p>默认情况下，OpenClaw 使用内置的 <code>legacy</code> 上下文引擎进行组装和压缩。如果您安装提供 <code>kind: &quot;context-engine&quot;</code> 的插件并使用 <code>plugins.slots.contextEngine</code> 选择它，OpenClaw 将上下文组装、<code>/compact</code> 和相关子代理上下文生命周期钩子委托给该引擎。<code>ownsCompaction: false</code> 不会自动回退到旧版引擎；活动引擎仍必须正确实现 <code>compact()</code>。请参阅<a href="/concepts/context-engine.html">上下文引擎</a>了解完整的可插拔接口、生命周期钩子和配置。</p><h2 id="context-实际报告什么" tabindex="-1"><code>/context</code> 实际报告什么 <a class="header-anchor" href="#context-实际报告什么" aria-label="Permalink to &quot;\`/context\` 实际报告什么&quot;">​</a></h2><p><code>/context</code> 优先使用最新的<strong>运行构建的</strong>系统提示报告（如果可用）：</p><ul><li><code>System prompt (run)</code> = 从最后一个嵌入式（工具型）运行捕获并持久化在会话存储中。</li><li><code>System prompt (estimate)</code> = 在没有运行报告时或在运行不生成报告的 CLI 后端时动态计算。</li></ul><p>无论哪种方式，它都报告大小和主要贡献者；它<strong>不</strong>转储完整的系统提示或工具模式。</p>`,47)])])}const m=s(t,[["render",l]]);export{u as __pageData,m as default};
